   input: [1, 8, 4, 5, 1]
   output: 3.8
   input: [2, 2, 2, 3]
   output: 2.25
*/
inline double average(std::vector<double> const& x) {
    if (x.empty()) return 0.0;               // handle empty vector safely
    double sum = 0.0;

    #pragma omp parallel for reduction(+:sum) schedule(static)
