/* Count the number of edges in the directed graph defined by the
   adjacency matrix A.  A is an NxN matrix stored in row‑major
   order.  The implementation is fully parallelized with OpenMP
   while preserving exact semantics. */
int edgeCount(const std::vector<int> &A, size_t N)
{
    int count = 0;
    #pragma omp parallel for reduction(+:count) schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int *row = A.data() + i * static_cast<int>(N);
        for (int j = 0; j < static_cast<int>(N); ++j) {
            if (row[j] == 1) {
                ++count;
            }
        }
    }
    return count;
}
