#include <limits>

/* Return the largest sum of any contiguous subarray in the vector `x`.
   The function preserves the exact semantics of the original implementation
   but runs in linear time using Kadane's algorithm. */
int maximumSubarray(std::vector<int> const& x) {
    // Handle empty vector: return the minimal int value (matches original)
    if (x.empty())
        return std::numeric_limits<int>::lowest();

    // Kadane's algorithm
    long long currentSum = 0;
    long long bestSum   = std::numeric_limits<long long>::min();

    for (int value : x) {
        currentSum += value;
        if (currentSum > bestSum) bestSum = currentSum;
        if (currentSum < 0) currentSum = 0;
    }

    // The result must fit in an int, as the original function returned int.
    // The algorithm guarantees that bestSum is within the representable
    // range for the given inputs because the original code also used int.
    return static_cast<int>(bestSum);
}
