#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    std::size_t row, column;
    double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N. */
inline void spmv(double alpha,
                 const std::vector<COOElement>& A,
                 const std::vector<double>& x,
                 double beta,
                 std::vector<double>& y,
                 std::size_t /*M*/, std::size_t /*N*/) noexcept
{
    // Scale y by beta in parallel
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        y[i] *= beta;
    }

    // Accumulate contributions from A in parallel using static scheduling
    #pragma omp parallel for schedule(static)
    for (std::size_t e = 0; e < A.size(); ++e) {
        // Direct memory accesses; the original code performed bounds checks which are omitted
        // for performance; indices are assumed to be valid by contract.
        const COOElement& a_ij = A[e];
        y[a_ij.row] += alpha * a_ij.value * x[a_ij.column];
    }
}
