#pragma once
#include <algorithm>
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Compute the highest node degree in an undirected graph whose adjacency
 * matrix is stored in a flat row‑major vector `A` of size N*N.
 *
 * The function is fully vectorised and parallelised with OpenMP.
 * It returns the maximum degree across all nodes.
 */
int maxDegree(const std::vector<int> &A, size_t N) {
    int highestDegree = 0;

    // Parallel over rows with a reduction on the maximum value.
    #pragma omp parallel for reduction(max:highestDegree) schedule(static)
    for (long long i = 0; i < static_cast<long long>(N); ++i) {
        const int *row = &A[i * N];
        int degree = 0;

        // Vectorised accumulation – loop unrolled by factor 4.
        size_t j = 0;
        size_t block = N & ~3ULL;          // largest multiple of 4 <= N
        for (; j < block; j += 4) {
            degree += row[j] + row[j+1] + row[j+2] + row[j+3];
        }
        for (; j < N; ++j) {
            degree += row[j];
        }

        if (degree > highestDegree) highestDegree = degree;
    }

    return highestDegree;
}
