    std::vector<std::array<std::size_t, 4>> threadBins(nthreads, {0, 0, 0, 0});

    #pragma omp parallel
    {
        const std::size_t tid = omp_get_thread_num();
        const std::size_t stride = omp_get_num_threads();
        std::array<std::size_t, 4> &local = threadBins[tid];

