16_graph_largest_component:
```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <stack>
#include <cstddef>

/* Return the number of vertices in the largest component of the graph defined by the
   adjacency matrix A. A is an NxN matrix stored in row‑major order. */
int largestComponent(std::vector<int> const& A, size_t N)
{
    // use a byte per visited flag for cache friendliness
    std::vector<char> visited(N, 0);
    int maxCount = 0;

    std::vector<int> stack;
    stack.reserve(N);

    for (size_t start = 0; start < N; ++start) {
        if (visited[start]) continue;

        int count = 0;
        stack.push_back(static_cast<int>(start));
        visited[start] = 1;

        while (!stack.empty()) {
            int v = stack.back();
            stack.pop_back();

            ++count;

            // scan row v for neighbours
            const int* row = &A[v * N];
            for (size_t to = 0; to < N; ++to) {
                if (row[to] && !visited[to]) {
                    visited[to] = 1;
                    stack.push_back(static_cast<int>(to));
                }
            }
        }

        if (count > maxCount) maxCount = count;
    }

    return maxCount;
}
