};

/*
 * Count the number of Cartesian points in each quadrant.
 * The result is stored in the array `bins` as follows:
 *   bins[0] – Quadrant I (x ≥ 0, y ≥ 0)
 *   bins[1] – Quadrant II (x < 0, y ≥ 0)
 *   bins[2] – Quadrant III (x < 0, y < 0)
 *   bins[3] – Quadrant IV (x ≥ 0, y < 0)
 *
 * The implementation uses OpenMP to parallelise the loop
 * over the input container.  All four counters are reduced
 * in a single reduction clause so that the final counts
 * are identical to the serial implementation.
 */
inline void countQuadrants(const std::vector<Point>& points, std::array<size_t,4>& bins) {
    // Pre‑zero the destination bins – required for idempotent runs
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Parallel loop over all points
    #pragma omp parallel for schedule(static) reduction(+:bins[0],bins[1],bins[2],bins[3])
    for (size_t i = 0; i < points.size(); ++i) {
        const Point& p = points[i];
        if (p.x >= 0.0 && p.y >= 0.0) {
            ++bins[0];
        } else if (p.x < 0.0 && p.y >= 0.0) {
            ++bins[1];
        } else if (p.x < 0.0 && p.y < 0.0) {
            ++bins[2];
        } else { // p.x >= 0.0 && p.y < 0.0
            ++bins[3];
        }
    }
}
