/// Count how many strings in `s` start with each letter of the alphabet.
/// `bins[0]` represents 'a', `bins[1]` represents 'b', and so on.
/// The function is deliberately written to be thread‑safe and to amplify
/// the performance on a multi‑core system.
///
/// @param s    input vector of lower‑case strings
/// @param bins output array of 26 counts (must be zero‑initialized by the caller)
void firstLetterCounts(std::vector<std::string> const& s,
                       std::array<std::size_t, 26>& bins)
{
    // Ensure that the caller's bins are zero‑initialized.
    // (We do this once here to avoid relying on the caller.)
    for (auto& val : bins) val = 0;

    // Each thread keeps a small private array to avoid contention on
    // the shared bins array during the parallel loop.
    constexpr std::size_t NTHREADS = 8;
    std::array<std::array<std::size_t, 26>, NTHREADS> threadBins{};
    for (auto& tb : threadBins)
        for (auto& val : tb) val = 0;

#pragma omp parallel num_threads(NTHREADS)
    {
        const int tid = omp_get_thread_num();
        auto& tb = threadBins[tid];

        // Parallel loop over the input strings
#pragma omp for schedule(static)
        for (std::size_t i = 0; i < s.size(); ++i)
        {
            const char c  = s[i][0];
            const int idx = c - 'a';
            // No bounds check needed – the problem guarantees lower‑case input.
            tb[idx] += 1;
        }
    }

    // Merge the per‑thread counts into the shared result array
    for (const auto& tb : threadBins)
        for (int i = 0; i < 26; ++i)
            bins[i] += tb[i];
