```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>
#include <immintrin.h>

/*
 * Compute the ReLU function on every element of x.
 * Elements less than zero become zero, elements greater than
 * or equal to zero stay unchanged.
 *
 * The function is vectorised with AVX2 and parallelised with OpenMP.
 * The original semantics are preserved – the input vector is modified in place.
 */
inline void relu(std::vector<double> &x)
{
    const std::size_t n = x.size();
    const double *restrict in  = x.data();
    double *restrict out = x.data();

    const std::size_t vecSize = 4;          // AVX2 processes 4 doubles per vector
    const std::size_t unroll = 2;           // unroll 2 vectors per loop
    const std::size_t batch  = vecSize * unroll;
    const std::size_t tail    = n % batch;

    const __m256d zero = _mm256_setzero_pd();

 #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i + batch <= n; i += batch) {
        // two AVX2 loads per iteration
        __m256d a1 = _mm256_loadu_pd(in + i);
        __m256d a2 = _mm256_loadu_pd(in + i + vecSize);

        // max with zero
        __m256d r1 = _mm256_max_pd(a1, zero);
        __m256d r2 = _mm256_max_pd(a2, zero);

        // store results
        _mm256_storeu_pd(out + i, r1);
        _mm256_storeu_pd(out + i + vecSize, r2);
    }

    // handle remaining elements (if any) with a scalar loop
    for (std::size_t i = n - tail; i < n; ++i) {
        out[i] = (in[i] > 0.0) ? in[i] : 0.0;
    }
}
