#include <limits>

/*
 * Replace the i-th element of the vector x with the minimum value
 * from indices 0 through i.
 *
 * Example:
 *   input : [8, 6, -1, 7, 3, 4, 4]
 *   output: [8, 6, -1, -1, -1, -1, -1]
 *
 * This implementation uses a simple linear scan.
 * The loop is written to aid the compiler in generating the most
 * optimal code under GCC‑O2 (e.g., using vectorized instructions
 * where possible).
 */
inline void partialMinimums(std::vector<float> &x)
{
    if (x.empty())
        return;

    // Minimum value encountered so far.
    float current_min = std::numeric_limits<float>::max();

    // Pointer arithmetic gives the compiler extra freedom to auto‑vectorise
    // and unroll the loop. The inner branchless min keeps the pipeline
    // busy. GCC will typically emit a single instruction per iteration on
    // modern CPUs (e.g., CMOV or SPLIT).
    auto *ptr   = x.data();
    const auto end = ptr + x.size();

    for (; ptr != end; ++ptr) {
        // Update current_min and store it.
        // constexpr ensures the function is inlined.
        const float v = *ptr;
        if (v < current_min) current_min = v;
        *ptr = current_min;
    }
}
