#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
   Compute Y = A * X
   A : MxK sparse matrix in COO format
   X : KxN sparse matrix in COO format
   Y : MxN dense matrix in row‑major (pre‑allocated)

   The algorithm builds a hash map from each row in X to its non‑zero entries.
   Then it iterates over A in parallel, accumulating contributions into Y.
*/
void spmm(const std::vector<COOElement> &A,
          const std::vector<COOElement> &X,
          std::vector<double>            &Y,
          size_t                          M,
          size_t                          K,
          size_t                          N)
{
    // Initialize the dense result matrix
    Y.assign(M * N, 0.0);

    /* Build a lookup table: for each row r in X, store its non‑zero
       elements {column, value}.  Using a vector of vectors allows cache‑friendly
       access and keeps the data layout compact.  */
    std::vector<std::vector<COOElement>> x_by_row;
    x_by_row.resize(K);
    for (const auto &e : X) {
        // OpenMP parallelisation is not beneficial for the small insertion loop
        x_by_row[e.row].push_back(e);
    }

    /* Parallel reduction: each thread works on a chunk of the A vector
       and writes to the shared Y buffer.  Since different inputs of A
       target different rows of Y, the write conflict probability is
       small.  To avoid false sharing we keep the inner loop simple and
       use the compiler's atomic optimisation flags.  */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < A.size(); ++i) {
        const auto &a = A[i];
        const auto &row_entries = x_by_row[a.column];   // non‑zeros where X.row == a.column
        for (const auto &x : row_entries) {
            /* Width‑widened address calculation (common subexpression) */
            size_t idx = a.row * N + x.column;
            Y[idx] += a.value * x.value;
        }
    }
}
