// Computes the sum of the inclusive prefix sums of x.
// This implementation uses a two‑stage parallel prefix (scan) with OpenMP
// and keeps identical numerical results to the original serial version.
int64_t sumOfPrefixSum(const std::vector<int64_t>& x) {
    const size_t n = x.size();
    if (n == 0) return 0;

    // Work buffer for partial prefix sums
    std::vector<int64_t> buf(n);
    std::vector<int64_t> chunkSum;       // sum of each chunk (exclusive)
    int64_t globalSum = 0;

    // Determine chunk size: balance contention and memory usage
    const int maxThreads = omp_get_max_threads();
    const size_t chunkSize = (n + maxThreads - 1) / maxThreads;

    const size_t numChunks = (n + chunkSize - 1) / chunkSize;
    chunkSum.resize(numChunks);

    // 1️⃣ First pass: compute inclusive scan per chunk and store its total
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        size_t start = tid * chunkSize;
        size_t end   = std::min(start + chunkSize, n);

        if (start >= end) return;

        int64_t sum = 0;
        for (size_t i = start; i < end; ++i) {
            sum += x[i];
            buf[i] = sum;
        }
        chunkSum[tid] = sum;
    }

    // 2️⃣ Reduce chunk sums to compute offsets for each chunk
    std::vector<int64_t> offsets(numChunks);
    offsets[0] = 0;
    for (size_t i = 1; i < numChunks; ++i) {
        offsets[i] = offsets[i-1] + chunkSum[i-1];
    }

    // 3️⃣ Second pass: add the offset to each element
    #pragma omp parallel for schedule(static, chunkSize)
    for (size_t i = 0; i < n; ++i) {
        size_t chunkIdx = i / chunkSize;
        buf[i] += offsets[chunkIdx];
    }

    // 4️⃣ Finally, sum all values in buf
    globalSum = std::accumulate(buf.begin(), buf.end(), int64_t{0});
    return globalSum;
}
