/* Compute the reverse prefix sum of the vector x into output.
   The output[i] contains the sum of x[i]..x[n-1].
   The function preserves the exact behavior of the original
   serial implementation but exploits multi‑threading for speed. */
inline void reversePrefixSum(std::vector<int> const& x, std::vector<int> &output) {
    const std::size_t n = x.size();
    if (n == 0) { output.clear(); return; }

    output.resize(n);

    /* 1. Compute the sum of each chunk in parallel. */
    const std::size_t blockSize = (n + omp_get_max_threads() - 1) / omp_get_max_threads();
    std::vector<long long> blockSum(omp_get_max_threads());

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::size_t start = tid * blockSize;
        std::size_t end   = std::min(start + blockSize, n);
        long long localSum = 0;
        for (std::size_t i = start; i < end; ++i) localSum += x[i];
        blockSum[tid] = localSum;
    }

    /* 2. Compute the suffix partial sums for the blocks. */
    std::vector<long long> blockSuffix(omp_get_max_threads());
    long long acc = 0;
    for (int i = int(blockSum.size()) - 1; i >= 0; --i) {
        acc += blockSum[i];
        blockSuffix[i] = acc;
    }

    /* 3. Compute the final suffix sum per element. */
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::size_t start = tid * blockSize;
        std::size_t end   = std::min(start + blockSize, n);

        long long partial = 0;
        for (std::size_t i = start; i < end; ++i) {
            partial += x[i];
            output[i] = static_cast<int>(blockSuffix[tid] - partial + x[i]); // inclusive
        }
    }
}
