#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

// Compute the discrete Fourier transform of x.
// The result is stored in output *exactly* as in the original implementation.
// Parallelised with OpenMP and optimised for speed.
void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output)
{
    const int N = static_cast<int>(x.size());
    output.assign(N, std::complex<double>(0.0, 0.0));

    const double two_pi = 2.0 * M_PI;
    const double inv_N   = 1.0 / static_cast<double>(N);

    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k)
    {
        std::complex<double> sum(0.0, 0.0);

        // Using a local variable for k * inv_N to reduce computed expressions
        const double k_over_N = static_cast<double>(k) * inv_N;

        for (int n = 0; n < N; ++n)
        {
            const double angle = two_pi * n * k_over_N;
            const double c_re  = std::cos(angle);
            const double c_im  = -std::sin(angle);          // Euler: e^{-iθ}
            sum += std::complex<double>(x[n] * c_re, x[n] * c_im);
        }
        output[k] = sum;
    }
}
