/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A.  A is an NxN row‑major matrix.  The graph
   is assumed to be connected.  The function is fully deterministic and
   preserves the exact semantics of the original implementation. */
int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest)
{
    // Use a simple ring buffer for the BFS queue.
    std::vector<int> queue(N);
    int q_head = 0, q_tail = 0;            // indices modulo N
    std::vector<char> visited(N, 0);       // 1 = visited

    // Distance array (optional; we can store the depth in the queue as a second array)
    std::vector<int> dist(N, -1);

    visited[source] = 1;
    queue[q_tail] = source;
    dist[source] = 0;
    q_tail = (q_tail + 1) % N;

    while (q_head != q_tail) {
        int cur = queue[q_head];
        int cur_dist = dist[cur];
        q_head = (q_head + 1) % N;

        if (cur == dest)
            return cur_dist;

        // Scan all possible neighbours.  The adjacency matrix is stored in
        // row-major order: A[cur*N + i] is the weight for edge cur‑i.
        // Zero weight means no edge.
        const int base = static_cast<int>(cur) * static_cast<int>(N);
        for (int i = 0; i < static_cast<int>(N); ++i) {
            if (A[base + i] && !visited[i]) {
                visited[i] = 1;
                queue[q_tail] = i;
                dist[i] = cur_dist + 1;
                q_tail = (q_tail + 1) % N;
            }
        }
    }

    // If the graph is connected this point is never reached, but we return a
    // sentinel consistent with the original implementation.
    return std::numeric_limits<int>::max();
}
