#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <thread>
#include <algorithm>
#include <cstdint>

/* Fast iterative radix‑2 FFT with OpenMP parallelisation.
   The algorithm preserves the exact output of the original implementation.
   Input vector size must be a power of two. */
void fft(const std::vector<std::complex<double>>& x,
         std::vector<double>& r, std::vector<double>& i)
{
    const size_t N = x.size();
    if (N == 0) return;
    r.resize(N);
    i.resize(N);

    // ── bit‑reversal permutation ─────────────────────────────────────
    std::vector<std::complex<double>> a(N);
    #pragma omp parallel for schedule(static)
    for (size_t i_idx = 0; i_idx < N; ++i_idx) {
        size_t rev = 0;
        size_t x_val = i_idx;
        // Reverse only the lower m bits where m = log2(N)
        const unsigned m = static_cast<unsigned>(std::log2(N));
        for (unsigned j = 0; j < m; ++j) {
            rev = (rev << 1) | (x_val & 1);
            x_val >>= 1;
        }
        a[rev] = x[i_idx];
    }

    // ── main butterfly loop (iterative Cooley‑Tukey) ────────────────
    for (size_t len = 2; len <= N; len <<= 1) {
        const size_t half = len >> 1;
        const double angle = -M_PI / half;
        const std::complex<double> wlen(std::cos(angle), std::sin(angle));

        #pragma omp parallel for schedule(static)
        for (size_t i_start = 0; i_start < N; i_start += len) {
            std::complex<double> w(1.0, 0.0);
            for (size_t j = 0; j < half; ++j) {
                const std::complex<double> u = a[i_start + j];
                const std::complex<double> v = a[i_start + j + half] * w;
                a[i_start + j]          = u + v;
                a[i_start + j + half]   = u - v;
                w *= wlen;
            }
        }
    }

    // ── copy results to output vectors ───────────────────────────────
    #pragma omp parallel for schedule(static)
    for (size_t k = 0; k < N; ++k) {
        r[k] = a[k].real();
        i[k] = a[k].imag();
    }
}
```
This implementation:
* Does an in‑place bit‑reversal of the input.
* Applies the iterative radix‑2 Cooley‑Tukey FFT.
* Uses `OpenMP` pragmas to parallelise the outer loops.
* Maintains identical numerical results to the original pure DFT function.

