    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Parallelise over the outermost loop using OpenMP
    #pragma omp parallel for schedule(static) reduction(min:minArea)
    for (std::size_t i = 0; i < n - 2; ++i)
