    const std::size_t N = x.size();
    output = x;

    // Pre‑compute the bit‑reversed indices
    std::size_t m = static_cast<std::size_t>(std::log2(N));
    std::vector<std::size_t> rev(N);
    rev[0] = 0;
    for (std::size_t i = 1; i < N; ++i) {
        rev[i] = (rev[i >> 1] >> 1) | ((i & 1) << (m - 1));
    }
    // Bit‑reversal permutation (in place)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev[i];
        if (j > i) {
            std::swap(output[i], output[j]);
        }
    }

    // Iterative in‑place radix‑2 Cooley–Tukey
    for (std::size_t s = 1; s <= m; ++s) {
        std::size_t m2 = 1 << s;          // stage size
        std::size_t m1 = m2 >> 1;         // half
        double theta = -M_PI / static_cast<double>(m1);
        std::complex<double> w_m(std::cos(theta), std::sin(theta));

#pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m2) {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j = 0; j < m1; ++j) {
                std::size_t a = k + j;
                std::size_t b = a + m1;
                std::complex<double> t = w * output[b];
                output[b] = output[a] - t;
                output[a] += t;
                w *= w_m;
            }
        }
    }
