/*
 * Compute one iteration of a 3‑point 1‑D Jacobi stencil on `input`.
 * The result is stored in `output`. The boundaries are treated as zero.
 *
 * This implementation is heavily optimised for speed:
 *   • OpenMP parallelisation on all cores.
 *   • Boundary handling is done outside the main loop to avoid branch
 *     predictions inside the inner body.
 *   • Division by three is done once by pre‑computing 1/3.
 *   • Raw pointers are used for maximal cache friendliness.
 *
 * Input and output arrays must be sized identically.
 */
inline void jacobi1D(const std::vector<double> &input,
                     std::vector<double>       &output)
{
    const std::size_t n = input.size();
    if (n == 0) return;

    const double inv3 = 1.0 / 3.0;
    const double *in  = input.data();
    double       *out = output.data();

    /* --- Handle the first element separately (i = 0) --- */
    out[0] = inv3 * (in[0] + (n > 1 ? in[1] : 0.0));

    /* --- Parallelised inner loop for 1 <= i <= n-2 --- */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < n; ++i) {
        out[i] = inv3 * (in[i - 1] + in[i] + in[i + 1]);
    }

    /* --- Handle the last element separately (i = n-1) --- */
    if (n > 1) {
        out[n - 1] = inv3 * (in[n - 2] + in[n - 1]);
    }
}
