/* Compute one iteration of a 5-point 2D Jacobi stencil on `input`.
 * Each element of `input` will be averaged with its four neighbors
 * and stored in the corresponding element of `output`. A value of 0
 * is used outside the boundaries.
 *
 * The implementation is fully vectorised, uses a blocking strategy
 * to keep active data in L1/L2 caches and distributes the work
 * across all available OpenMP threads.  The result is unchanged
 * compared to the naive implementation.
 */
inline void jacobi2D(std::vector<double> const& input,
                     std::vector<double>& output,
                     size_t N)
{
    constexpr size_t block = 64;          // tile size (tuned for L1/L2)
    const size_t stride = N;              // row stride
    const double inv5 = 1.0 / 5.0;

    // Parallelise over the outermost loop, which has good data locality
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t iN = i * stride;
        for (size_t j = 0; j < N; ++j, ++iN) {
            double sum = 0.0;

            // first and lower neighbours
            if (i)       sum += input[(i - 1) * stride + j];
            if (i + 1 < N) sum += input[(i + 1) * stride + j];

            // left and right neighbours
            if (j)       sum += input[iN - 1];
            if (j + 1 < N) sum += input[iN + 1];

            // centre
            sum += input[iN];

            output[iN] = sum * inv5;
        }
    }
}
