#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <execution>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax = b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   The function preserves the exact behaviour of the reference implementation.
*/
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    // Flat dense matrix in row major order: matrix[row * N + col]
    std::vector<double> matrix(N * N, 0.0);

    // Fill the matrix with the values from A   (parallelised)
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const COOElement& e = A[idx];
        matrix[e.row * N + e.column] = e.value;
    }

    // Copy RHS
    std::vector<double> b_copy = b;
    x.assign(N, 0.0);

    // Gaussian elimination with partial pivoting
    for (size_t i = 0; i < N; ++i) {
        // --- Pivot selection ---------------------------------------------
        size_t maxRow = i;
        double maxEl  = std::fabs(matrix[i * N + i]);

        for (size_t k = i + 1; k < N; ++k) {
            double cur = std::fabs(matrix[k * N + i]);
            if (cur > maxEl) {
                maxEl = cur;
                maxRow = k;
            }
        }

        // --- Swap rows i and maxRow --------------------------------------
        if (maxRow != i) {
            #pragma omp parallel for schedule(static)
            for (size_t col = i; col < N; ++col) {
                std::swap(matrix[maxRow * N + col], matrix[i * N + col]);
            }
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        // --- Eliminate below ---------------------------------------------
        double pivot = matrix[i * N + i];
        for (size_t k = i + 1; k < N; ++k) {
            double c = -matrix[k * N + i] / pivot;
            matrix[k * N + i] = 0.0; // explicit zero
            // row‑wise update
            #pragma omp simd
            for (size_t j = i + 1; j < N; ++j) {
                matrix[k * N + j] += c * matrix[i * N + j];
            }
            b_copy[k] += c * b_copy[i];
        }
    }

    // Back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = b_copy[i];
        for (int j = i + 1; j < static_cast<int>(N); ++j) {
            sum -= matrix[i * N + j] * x[j];
        }
        x[i] = sum / matrix[i * N + i];
    }
}
