struct Element {
    std::size_t index;
    double value;
};

/*
 * Compute z = alpha * x + y where x and y are sparse vectors.
 * The result is accumulated into the dense vector z.
 * For performance, the operation is parallelised with OpenMP.
 * Atomic updates are used to avoid race conditions when multiple
 * threads write to the same index of z.
 */
inline void sparseAxpy(double alpha,
                       const std::vector<Element> &x,
                       const std::vector<Element> &y,
                       std::vector<double> &z)
{
    /* Ensure z is large enough */
    std::size_t maxIdx = 0;
    if (!x.empty())
        maxIdx = std::max(maxIdx, x.back().index);
    if (!y.empty())
        maxIdx = std::max(maxIdx, y.back().index);
    if (z.size() <= maxIdx)
        z.resize(maxIdx + 1, 0.0);

    /* Parallelise over the two sparsity lists */
    #pragma omp parallel
    {
        /* each thread processes a disjoint sub‑range of x and y */
        #pragma omp single nowait
        {
            /* Compute total number of merges */
            const std::size_t nx = x.size();
            const std::size_t ny = y.size();

            /* Threshold for tasking: avoid excessive overhead for tiny lists */
            const std::size_t THRESHOLD = 64;

            /* Create a recursive lambda for merge work */
            std::function<void(std::size_t, std::size_t, std::size_t, std::size_t)> merge;
            merge = [&](std::size_t xiL, std::size_t xiR, std::size_t yiL, std::size_t yiR)
            {
                /* Base case: small ranges -> serial work */
                if ((xiR - xiL) + (yiR - yiL) <= THRESHOLD)
                {
                    std::size_t xi = xiL, yi = yiL;
                    while (xi < xiR && yi < yiR)
                    {
                        if (x[xi].index < y[yi].index)
                        {
                            #pragma omp atomic
                            z[x[xi].index] += alpha * x[xi].value;
                            ++xi;
                        }
                        else if (x[xi].index > y[yi].index)
                        {
                            #pragma omp atomic
                            z[y[yi].index] += y[yi].value;
                            ++yi;
                        }
                        else
                        {
                            #pragma omp atomic
                            z[x[xi].index] += alpha * x[xi].value + y[yi].value;
                            ++xi;
                            ++yi;
                        }
                    }
                    while (xi < xiR)
                    {
                        #pragma omp atomic
                        z[x[xi].index] += alpha * x[xi].value;
                        ++xi;
                    }
                    while (yi < yiR)
                    {
                        #pragma omp atomic
                        z[y[yi].index] += y[yi].value;
                        ++yi;
                    }
                    return;
                }

                /* Divide the larger of the two ranges */
                if (xiR - xiL >= yiR - yiL)
                {
                    std::size_t mid = xiL + (xiR - xiL) / 2;
                    #pragma omp task
                    merge(xiL, mid, yiL, yiR);
                    #pragma omp task
                    merge(mid, xiR, yiL, yiR);
                }
                else
                {
                    std::size_t mid = yiL + (yiR - yiL) / 2;
                    #pragma omp task
                    merge(xiL, xiR, yiL, mid);
                    #pragma omp task
                    merge(xiL, xiR, mid, yiR);
                }
            };

            /* Kick off the initial merge task */
            #pragma omp task
            merge(0, nx, 0, ny);
        }
        #pragma omp taskwait
    }
}
