struct Point {
    double x, y;
};

inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Find the set of points that defined the smallest convex polygon that contains all the points in the vector points. Store the result in `hull`. */
void convexHull(std::vector<Point> const& points, std::vector<Point> &hull) {
    size_t n = points.size();
    if (n < 3) {
        hull = points;
        return;
    }

    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        return a.x < b.x || (a.x == b.x && a.y < b.y);
    });

    std::vector<Point> h;
    h.reserve(n * 2);

    // Build lower hull
    for (size_t i = 0; i < n; ++i) {
        while (h.size() >= 2 && cross(h[h.size() - 2], h[h.size() - 1], pts[i]) <= 0)
            h.pop_back();
        h.push_back(pts[i]);
    }

    // Build upper hull
    size_t t = h.size() + 1;
    for (size_t i = n; i-- > 0;) {          // i goes n-1 .. 0
        while (h.size() >= t && cross(h[h.size() - 2], h[h.size() - 1], pts[i]) <= 0)
            h.pop_back();
        h.push_back(pts[i]);
    }

    // Remove the last point because it is duplicated
    if (!h.empty())
        h.pop_back();

    hull.swap(h);
}
