/* Compute the prefix sum of the vector x into output.
   Example:
   input: [1, 7, 4, 6, 6, 2]
   output: [1, 8, 12, 18, 24, 26]
*/
inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output)
{
    const std::size_t n = x.size();
    output.assign(n, 0);
    if (n == 0) return;

    int64_t* out = output.data();
    const int64_t* in = x.data();

    /* First pass: compute partial sums per chunk */
    const int num_threads = omp_get_max_threads();
    std::vector<int64_t> partial(num_threads, 0);

    #pragma omp parallel
    {
        const int tid  = omp_get_thread_num();
        const int nth = omp_get_num_threads();
        const std::size_t chunk = (n + nth - 1) / nth;
        const std::size_t start = static_cast<std::size_t>(tid) * chunk;
        const std::size_t end   = std::min(start + chunk, n);

        int64_t local = 0;
        for (std::size_t i = start; i < end; ++i) {
            local += in[i];
            out[i] = local;
        }
        partial[tid] = local;
    }

    /* Second pass: prefix the chunk sums */
    int64_t acc = 0;
    for (int i = 0; i < num_threads; ++i) {
        int64_t tmp = partial[i];
        partial[i] = acc;
        acc += tmp;
    }

    /* Third pass: add the offset to each chunk (except the first) */
    #pragma omp parallel
    {
        const int tid  = omp_get_thread_num();
        const int nth = omp_get_num_threads();
        const std::size_t chunk = (n + nth - 1) / nth;
        const std::size_t start = static_cast<std::size_t>(tid) * chunk;
        const std::size_t end   = std::min(start + chunk, n);

        const int64_t add = partial[tid];
        for (std::size_t i = start; i < end; ++i) {
            out[i] += add;
        }
    }
}
