constexpr size_t CACHE_LINE_BYTES = 64;          // Typical cache line size
constexpr size_t BLOCK_SIZE       = 64;           // Block size in rows (tuneable)
constexpr size_t VECTOR_WIDTH     = 4;            // Number of doubles that fit into 32‑byte SIMD registers

// Helper to unroll a vector multiplication for a single row
inline void mul_row(const double* a_row, const double* x, double* y, size_t N) {
    double sum = 0.0;
    size_t j = 0;
    // SIMD‑friendly unrolling
    for (; j + VECTOR_WIDTH <= N; j += VECTOR_WIDTH) {
        sum += a_row[j]     * x[j];
        sum += a_row[j + 1] * x[j + 1];
        sum += a_row[j + 2] * x[j + 2];
        sum += a_row[j + 3] * x[j + 3];
    }
    // Remaining tail
    for (; j < N; ++j) {
        sum += a_row[j] * x[j];
    }
    *y = sum;
}

// Main GEMV implementation
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> & y,
                 size_t M, size_t N) {

    // Safety checks (no-op in release builds)
#if !defined(NDEBUG)
    if (A.size() != M * N || x.size() != N || y.size() != M)
        throw std::invalid_argument("gemv: size mismatch");
#endif

    // Parallel over blocks of rows to improve cache locality
    #pragma omp parallel for schedule(static, 1)
    for (size_t i = 0; i < M; i += BLOCK_SIZE) {
        size_t i_max = std::min(i + BLOCK_SIZE, M);
        size_t row_offset = i * N;
        for (size_t r = i; r < i_max; ++r) {
            mul_row(&A[row_offset + (r - i) * N], x.data(), &y[r], N);
        }
    }
}
