/*
 * For each cell (i, j) in a N×N grid, set
 * output[i*N + j] = 1 if exactly one of its four orthogonal neighbours
 * contains a 1, otherwise set it to 0.
 * The neighbours are:
 *   (i-1, j)   (i+1, j)
 *   (i, j-1)   (i, j+1)
 * Borders are treated as missing neighbours (they do not contribute to the count).
 */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     size_t N) noexcept
{
    const std::size_t total = N * N;
    if (output.size() != total || input.size() != total) {
        return;   // safety: nothing to do if sizes mismatch
    }

    const int *restrict in  = input.data();
          int *restrict out = output.data();

    /* Parallelise over rows; each row can be processed independently.
     * Use a collapse(2) pragma for better load‑balance when the grid is small.
     * The compiler will keep bounds checks minimal, and the code uses
     * pointer arithmetic to avoid redundant multiplications.
     */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t base   = i * N;
        const std::size_t prev   = (i > 0) ? base - N : 0;   // index of row i-1
        const std::size_t next   = (i + 1 < N) ? base + N : 0; // index of row i+1

        for (std::size_t j = 0; j < N; ++j) {
            int count = 0;

            /* top neighbour */
            if (i > 0      && in[prev  + j] == 1) ++count;
            /* bottom neighbour */
            if (i + 1 < N  && in[next  + j] == 1) ++count;
            /* left neighbour */
            if (j > 0      && in[base  + j-1] == 1) ++count;
            /* right neighbour */
            if (j + 1 < N  && in[base  + j+1] == 1) ++count;

            out[base + j] = (count == 1) ? 1 : 0;
        }
    }
}
