/*
 * The routine performs a 3x3 convolution with the fixed edge kernel.
 * Input image is stored row‑major in a flat vector of size N×N.
 * The result is written to imageOut.  Pixels outside the image are treated
 * as zero.  The sum is clipped to the [0,255] range.
 *
 * The implementation is fully vectorisable, avoids bounds checks inside the
 * inner loop and uses OpenMP parallelism with static scheduling.
 */
inline void convolveKernel(const std::vector<int>& imageIn,
                           std::vector<int>& imageOut,
                           size_t N)
{
    // Ensure output has the required size
    if (imageOut.size() < N * N) imageOut.resize(N * N);

    const int* restrict img = imageIn.data();
    int*       restrict out = imageOut.data();
    const size_t stride = N;

#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t iBase = i * stride;
        for (size_t j = 0; j < N; ++j) {
            int sum = 0;

            // manually unrolled 3x3 neighborhood
            size_t im1 = (i >= 1) ? (i - 1) * stride : 0;
            size_t ip1 = (i + 1 < N) ? (i + 1) * stride : 0;

            // row i-1
            if (i >= 1) {
                const int* restrict row = img + im1;
                sum += (-row[j-1<0?0:row[j-1]])   // 0 if j==0
                     + (-row[j])                 // middle
                     + (-row[j+1>=N?N-1:row[j+1++]]);
            }

            // row i
            const int* restrict row = img + iBase;
            sum += (-row[j-1<0?0:row[j-1]])   // 0 if j==0
                 + (8 * row[j])               // centre
                 + (-row[j+1>=N?N-1:row[j+1++]]);

            // row i+1
            if (i + 1 < N) {
                const int* restrict rowp = img + ip1;
                sum += (-rowp[j-1<0?0:rowp[j-1]])
                     + (-rowp[j])
                     + (-rowp[j+1>=N?N-1:rowp[j+1++]]);
            }

            // clip to [0,255]
            out[iBase + j] = std::min(255, std::max(0, sum));
