// Find the index of the first even element.
// For performance we use AVX2 vectorisation to examine 8 ints at once.
// The algorithm first checks 8‑element blocks; if an even element is found,
// we decode the result to return the correct global index.
// This preserves the exact behaviour of the reference implementation.
size_t findFirstEven(const std::vector<int>& x) {
    const size_t n = x.size();
    size_t i = 0;

    // Process full 8‑int blocks with AVX2
    const size_t block = 8;
    const __m256i mask_even = _mm256_set1_epi32(0xFFFFFFFE); // 0xFE at low byte

    for (; i + block <= n; i += block) {
        __m256i v = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(x.data() + i));
        __m256i masked = _mm256_and_si256(v, mask_even);            // clears LSB
        __m256i cmp = _mm256_cmpeq_epi32(masked, v);                // 0xFFFFFFFF for evens

        int r = _mm256_movemask_epi8(cmp);                          // 1 per byte
        if (r != 0) {                                              // some even
            // Find lowest set byte
            int byte = __builtin_ctz(r);
            // Convert byte index to element index
            return i + byte / 4;
        }
    }

    // Handle remaining elements sequentially
    for (; i < n; ++i) {
        if ((x[i] & 1) == 0) {
            return i;
        }
    }
    return n;
}
