/*
 * Perform LU factorisation of an N×N matrix stored in row-major order.
 * The factorised L and U matrices overwrite the input matrix A.
 */
inline void luFactorize(std::vector<double>& A, size_t N) {
    const size_t stride = N;            // stride between rows
    const size_t bound  = N / 8 * 8;     // work on full 8‑element chunks first

    #pragma omp parallel
    for (size_t k = 0; k < N; ++k) {
        const double pivot = A[k * stride + k];

        // Work on the trailing sub‑matrix row by row
        #pragma omp for schedule(static, 1)
        for (size_t i = k + 1; i < N; ++i) {
            double* ai      = &A[i * stride];
            const double* ak = &A[k * stride];

            const double factor = ai[k] / pivot;
            ai[k] = factor;                     // store L(i,k)

            // vectorised inner cross‑product: U part update
            size_t j = k + 1;
            size_t end = bound + (k + 1);
            for (; j < end; j += 8) {
                // load 8 U elements, multiply, and subtract
                double t0 = ak[j]   * factor; double t1 = ak[j+1] * factor;
                double t2 = ak[j+2] * factor; double t3 = ak[j+3] * factor;
                double t4 = ak[j+4] * factor; double t5 = ak[j+5] * factor;
                double t6 = ak[j+6] * factor; double t7 = ak[j+7] * factor;

                ai[j]   -= t0; ai[j+1] -= t1;
                ai[j+2] -= t2; ai[j+3] -= t3;
                ai[j+4] -= t4; ai[j+5] -= t5;
                ai[j+6] -= t6; ai[j+7] -= t7;
            }
            for (; j < N; ++j) {
                ai[j] -= factor * ak[j];
            }
        }
    }
}
