 *
 * Examples:
 *   input : [3.1, 2.8, 9.1, 0.4, 3.14]
 *   output: [2, 1, 4, 0, 3]
 *   input : [100, 7.6, 16.1, 18, 7.6]
 *   output: [4, 0, 1, 2, 3]
 */
inline void ranks(std::vector<float> const& x, std::vector<std::size_t> &ranks_) {
    // Early‑exit for empty input
    if (x.empty()) {
        ranks_.clear();
        return;
    }

    // Allocate and initialise index vector
    std::vector<std::size_t> indices(x.size());
    std::iota(indices.begin(), indices.end(), 0);

    // Sort indices according to the corresponding values in `x`
    std::sort(indices.begin(), indices.end(),
              [&x](std::size_t i1, std::size_t i2) { return x[i1] < x[i2]; });

    // Resize output container to match input size
    ranks_.resize(x.size());

    // Parallel fill of the ranks array
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < indices.size(); ++i) {
        ranks_[indices[i]] = i;
    }
