struct Point
{
    double x, y;
};

/* Compute the Euclidean distance between two points without the
 * cost of two extra function calls. */
inline double dist(const Point& a, const Point& b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Cross product of AB × AC (signed area of the triangle). */
inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Return the perimeter of the smallest convex polygon that contains all
 * the points in the vector `points`.  The implementation uses the
 * monotone-chain algorithm (O(n log n)) with a few micro‑optimisations
 * (inlined helpers, cache‑friendly hull building, parallel distance
 * accumulation). */
double convexHullPerimeter(const std::vector<Point>& points)
{
    constexpr std::size_t minHullSize = 3;
    if (points.size() < minHullSize)
        return 0.0;

    /* ----- Step 1 – sort the points lexicographically ----- */
    std::vector<Point> pts = points;            // local copy
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b)
              { return a.x < b.x || (a.x == b.x && a.y < b.y); });

    /* ----- Step 2 – build the lower and upper hulls ----- */
    std::vector<Point> hull;
    hull.reserve(pts.size() * 2);              // upper bound

    /* lower hull */
    for (const auto& p : pts)
    {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull.back(), p) <= 0.0)
            hull.pop_back();
        hull.push_back(p);
    }

    /* upper hull (skip the first and last point to avoid duplicates) */
    for (auto it = pts.rbegin() + 1; it != pts.rend() - 1; ++it)
    {
        const auto& p = *it;
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull.back(), p) <= 0.0)
            hull.pop_back();
        hull.push_back(p);
    }

    /* The last point of the upper hull is the same as the first
     * point of the lower hull – remove it to avoid a duplicate. */
    hull.pop_back();

    /* ----- Step 3 – compute the perimeter ----- */
    double perimeter = 0.0;
    const std::size_t n = hull.size();

#pragma omp parallel for reduction(+:perimeter) schedule(static)
    for (std::size_t i = 0; i < n; ++i)
    {
        const std::size_t j = (i + 1) % n;   // next vertex (wrap-around)
        perimeter += dist(hull[i], hull[j]);
    }

    return perimeter;
}
