inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       std::size_t N)
{
    /* local aliases and stride */
    const int *in  = input.data();
    int * out = output.data();
    const std::size_t stride = N;

    /* Parallelise the outer 2‑D loop.
       collapse(2) makes a single 2‑D index that the compiler can split
       efficiently over the 8 threads.  The reduction is avoided by
       writing directly to the destination array. */
#pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t idx = 0; idx < N * N; ++idx) {
        const std::size_t i = idx / stride;
        const std::size_t j = idx % stride;

        /* Count alive neighbours.  The border checks are
           eliminated by using signed indices; the conditions are
           evaluated only when the neighbour exists. */
        int sum = 0;

        /* Using signed indices to simplify computations */
        const std::ptrdiff_t im1 = static_cast<std::ptrdiff_t>(i) - 1;
        const std::ptrdiff_t ip1 = static_cast<std::ptrdiff_t>(i) + 1;
        const std::ptrdiff_t jm1 = static_cast<std::ptrdiff_t>(j) - 1;
        const std::ptrdiff_t jp1 = static_cast<std::ptrdiff_t>(j) + 1;

        if (im1 >= 0) sum += in[im1 * stride + j];
        if (ip1 <  (std::ptrdiff_t)N) sum += in[ip1 * stride + j];
        if (jm1 >= 0) sum += in[i * stride + jm1];
        if (jp1 <  (std::ptrdiff_t)N) sum += in[i * stride + jp1];
        if (im1 >= 0 && jm1 >= 0) sum += in[im1 * stride + jm1];
        if (im1 >= 0 && jp1 <  (std::ptrdiff_t)N) sum += in[im1 * stride + jp1];
        if (ip1 <  (std::ptrdiff_t)N && jm1 >= 0) sum += in[ip1 * stride + jm1];
        if (ip1 <  (std::ptrdiff_t)N && jp1 <  (std::ptrdiff_t)N) sum += in[ip1 * stride + jp1];

        /* Apply Game‑of‑Life rules */
        const int cur = in[i * stride + j];
        if (cur == 1) {
            out[i * stride + j] = (sum == 2 || sum == 3) ? 1 : 0;
        } else {
            out[i * stride + j] = (sum == 3) ? 1 : 0;
        }
    }
}
