/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix. The matrices are
   stored in row‑major. The function keeps exactly the same semantics as the
   reference implementation: it adds the product into the existing value of C.
   The implementation below is highly optimized for x86‑64 CPUs with
   AVX2/AVX512 support, uses blocking for cache locality, and parallelises
   the outermost loop with OpenMP.
*/

static constexpr size_t BLOCK_SIZE_I = 64;   // block width for rows of A / C
static constexpr size_t BLOCK_SIZE_K = 64;   // block width for columns of A / rows of B
static constexpr size_t BLOCK_SIZE_J = 64;   // block width for columns of B / C

void gemm(std::vector<double> const& A,
          std::vector<double> const& B,
          std::vector<double> &C,
          size_t M, size_t K, size_t N)
{
    // Pointers to underlying data for faster indexing.
    const double *Adata = A.data();
    const double *Bdata = B.data();
          double *Cdata = C.data();

    // Parallelise over blocks of rows of A / C.
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BLOCK_SIZE_I) {
        size_t i_max = std::min(ii + BLOCK_SIZE_I, M);
        for (size_t kk = 0; kk < K; kk += BLOCK_SIZE_K) {
            size_t k_max = std::min(kk + BLOCK_SIZE_K, K);
            for (size_t jj = 0; jj < N; jj += BLOCK_SIZE_J) {
                size_t j_max = std::min(jj + BLOCK_SIZE_J, N);

                // Unrolled inner triple loop for the current block.
                for (size_t i = ii; i < i_max; ++i) {
                    double *Crow = Cdata + i * N + jj;
                    for (size_t k = kk; k < k_max; ++k) {
                        double a_val = Adata[i * K + k];
                        const double *Brow = Bdata + k * N + jj;
                        // SIMD-friendly loop over j within block.
                        for (size_t j = 0; j < (j_max - jj); ++j) {
                            Crow[j] += a_val * Brow[j];
                        }
                    }
                }
            }
        }
    }
}
