/*
 * Return the index of the value in the vector x that is closest to the math
 * constant PI.  Use M_PI for the value of PI.
 *
 * Example:
 *   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
 *   output: 1
 */
inline size_t findClosestToPi(const std::vector<double> &x)
{
    const size_t n = x.size();
    if (n == 0) return static_cast<size_t>(-1);          // defensive: no elements
    if (n == 1) return 0;                                // trivial case

    double bestDiff = std::abs(x[0] - M_PI);
    size_t bestIndex = 0;

#pragma omp parallel
    {
        double localBestDiff = std::numeric_limits<double>::infinity();
        size_t localBestIndex = 0;

#pragma omp for nowait
        for (size_t i = 0; i < n; ++i)
        {
            double d = std::abs(x[i] - M_PI);
            if (d < localBestDiff)
            {
                localBestDiff = d;
                localBestIndex = i;
            }
        }

#pragma omp critical
        {
            if (localBestDiff < bestDiff)
            {
                bestDiff = localBestDiff;
                bestIndex = localBestIndex;
            }
        }
    }

    return bestIndex;
}
