#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   The routine preserves the exact mathematical behaviour of the
   reference implementation but is tuned for speed on a modern
   x86‑64 processor with up to 8 OpenMP threads.
   The function is fully thread‑safe because all temporaries are local
   to the call. */
inline void solveLinearSystem(std::vector<double> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              size_t N)
{
    /* Make local copies to avoid modifying the input vectors. */
    std::vector<double> Acopy;
    std::vector<double> bcopy;
    Acopy.resize(N * N);
    bcopy  .resize(N);
    std::memcpy(Acopy.data(), A.data(), N * N * sizeof(double));
    std::memcpy(bcopy.data(),  b.data(), N * sizeof(double));

    /* Gaussian elimination with partial pivoting disabled
       (the original algorithm does not pivot).  The outer loop is
       inherently serial; the inner row operations can be parallelised. */
    for (size_t i = 0; i + 1 < N; ++i)
    {
        double pivot = Acopy[i * N + i];
        if (pivot == 0.0) return;           // singular matrix – original behaviour

        /* Parallelize the elimination of the rows below the pivot.
           Each thread works on a distinct row; the dependency chain
           between rows is respected by the natural order of the loop
           because only previously finished rows are used as source.
           The pragma also indicates a schedule that keeps data locality. */
        #pragma omp parallel for schedule(static,1)
        for (long long j = static_cast<long long>(i) + 1; j < static_cast<long long>(N); ++j)
        {
            double factor = Acopy[j * N + i] / pivot;
            for (size_t k = i; k < N; ++k)
                Acopy[j * N + k] -= factor * Acopy[i * N + k];
            bcopy[j] -= factor * bcopy[i];
        }
    }

    /* Back substitution: follows the same pattern as the original.  To
       eliminate false sharing, the result vector `x` is first filled
       with zeros; the last row is handled serially. */
    x.assign(N, 0.0);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i)
    {
        const double *Ai = &Acopy[i * N];
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j)
            sum += Ai[j] * x[j];
        x[i] = (bcopy[i] - sum) / Ai[i];
    }
}
