#include <cstddef>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
// Helper: bit‑reversal permutation.
// -----------------------------------------------------------------------------
inline void bit_reverse_permutation(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));
    std::size_t j = 0;
    for (std::size_t i = 0; i < N-1; ++i)
    {
        if (i < j)
            std::swap( x[i], x[j] );

        std::size_t m = N >> 1;
        while (j >= m && m > 0)
        {
            j -= m;
            m >>= 1;
        }
        j += m;
    }
}

// -----------------------------------------------------------------------------
// Forward FFT (radix‑2, decimation‑in‑time).
// -----------------------------------------------------------------------------
inline void fft_radix2(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));

    // Pre‑compute twiddle factors.
    std::vector<std::complex<double>> twiddles(logN);
    for (std::size_t s = 1; s <= logN; ++s)
        twiddles[s-1] = std::exp(std::complex<double>(0.0, -M_PI / (1ULL << (s-1))));

    // Bit‑reverse reorder.
    bit_reverse_permutation(x);

    // Iterative FFT.
    for (std::size_t s = 1; s <= logN; ++s)
    {
        const std::size_t m = 1ULL << s;
        const std::size_t halflen = m >> 1;
        const std::complex<double> w_m = twiddles[s-1];

        for (std::size_t k = 0; k < N; k += m)
        {
            std::complex<double> w = 1.0;
            for (std::size_t j = 0; j < halflen; ++j)
            {
                const std::size_t idx1 = k + j;
                const std::size_t idx2 = idx1 + halflen;

                const std::complex<double> t = w * x[idx2];
                x[idx2] = x[idx1] - t;
                x[idx1] += t;

                w *= w_m;
            }
        }
    }
}

// -----------------------------------------------------------------------------
// Wrapper: Forward FFT (matches original interface).
// -----------------------------------------------------------------------------
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    fft_radix2(x);
}

// -----------------------------------------------------------------------------
// Inverse FFT.
// -----------------------------------------------------------------------------
inline void ifft(std::vector<std::complex<double>>& x)
{
    // Conjugate.
    std::transform(std::execution::par_unseq,
                   x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    // Forward FFT.
    fft_radix2(x);

    // Conjugate again.
    std::transform(std::execution::par_unseq,
                   x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    // Scale.
    const double invN = 1.0 / static_cast<double>(x.size());
    std::transform(std::execution::par_unseq,
                   x.begin(), x.end(), x.begin(),
                   [invN](const std::complex<double>& v){ return v * invN; });
}
