/* Sort the vector x of complex numbers by their magnitude in ascending order.
   This implementation uses a parallel merge‑sort that contends with the
   OpenMP runtime.  The behaviour is identical to the original, but the
   sorting is performed in parallel on the available threads.
*/
namespace {
    // Helper: compare by magnitude
    inline bool cmp_mag(const std::complex<double>& a, const std::complex<double>& b) {
        return std::abs(a) < std::abs(b);
    }

    // Merge two already sorted ranges [first, mid) and [mid, last)
    void merge_ranges(std::vector<std::complex<double>>& data,
                      std::size_t first, std::size_t mid, std::size_t last,
                      std::vector<std::complex<double>>& temp) {
        std::size_t i = first, j = mid, k = first;
        while (i < mid && j < last) {
            temp[k++] = (std::abs(data[i]) < std::abs(data[j])) ? data[i++] : data[j++];
        }
        while (i < mid) temp[k++] = data[i++];
        while (j < last) temp[k++] = data[j++];
        std::copy(temp.begin() + first, temp.begin() + last, data.begin() + first);
    }

    // Parallel merge sort
    void parallel_merge_sort(std::vector<std::complex<double>>& data,
                             std::size_t first, std::size_t last,
                             std::vector<std::complex<double>>& temp,
                             int depth) {
        // Base case: small chunk, use std::sort
        constexpr std::size_t THRESHOLD = 1 << 12; // 4096
        if (last - first <= THRESHOLD) {
            std::sort(data.begin() + first, data.begin() + last, cmp_mag);
            return;
        }

        std::size_t mid = first + (last - first) / 2;
        if (depth > 0) {
            // Parallel recursion
#pragma omp task shared(data, temp) firstprivate(mid, last, depth)
            parallel_merge_sort(data, mid, last, temp, depth - 1);
            parallel_merge_sort(data, first, mid, temp, depth - 1);
#pragma omp taskwait
        } else {
            // Sequential recursion
            parallel_merge_sort(data, first, mid, temp, depth);
            parallel_merge_sort(data, mid, last, temp, depth);
        }

        // Merge the two sorted halves
        merge_ranges(data, first, mid, last, temp);
    }
}

void sortComplexByMagnitude(std::vector<std::complex<double>>& x) {
    const std::size_t n = x.size();
    if (n <= 1) return;

    std::vector<std::complex<double>> temp(n);

    // Determine recursion depth based on number of threads
    int num_threads = 1;
#pragma omp parallel
    {
#pragma omp single
        num_threads = omp_get_num_threads();
    }
    int depth = 0;
    while ((1 << depth) < num_threads) ++depth;
    --depth; // avoid too many tasks

#pragma omp parallel
    {
#pragma omp single
        parallel_merge_sort(x, 0, n, temp, depth);
    }
}
