    static inline uint32_t bitrev32(uint32_t x, uint32_t bits)
    {
        x = (rev8[x & 0xFF] << 24) |
            (rev8[(x >> 8) & 0xFF] << 16) |
            (rev8[(x >> 16) & 0xFF] << 8) |
            rev8[(x >> 24) & 0xFF];
        return x >> (32 - bits);
    }
