// ------------------------------------------------------------------
// Public FFT routine
// ------------------------------------------------------------------
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const uint32_t N = static_cast<uint32_t>(x.size());
    if (N <= 1) return;

    // --------------------------------------------------------------
    // 1. Pre‑compute twiddle tables
    // --------------------------------------------------------------
    const auto twiddles = detail::buildTwiddle(N);

    // --------------------------------------------------------------
    // 2. Bit‑reversal permutation (single‑threaded; cost is trivial)
    // --------------------------------------------------------------
    const uint32_t bits = static_cast<uint32_t>(std::log2(N));
    for (uint32_t i = 0; i < N; ++i)
    {
        uint32_t j = detail::bitrev32(i, bits);
        if (j > i)
            std::swap(x[i], x[j]);
    }

    // --------------------------------------------------------------
    // 3. Iterative radix‑2 FFT
    // --------------------------------------------------------------
    const uint32_t stages = bits;
    for (uint32_t stage = 1; stage <= stages; ++stage)
    {
        const uint32_t m = 1u << stage;          // size of sub‑FFT
        const uint32_t half = m >> 1;
        const auto& W = twiddles[stage-1];       // pre‑computed twiddles

        // Parallelise over the outer butterfly loops
        #pragma omp parallel for schedule(static)
        for (uint32_t k = 0; k < N; k += m)
        {
            for (uint32_t j = 0; j < half; ++j)
            {
                const std::complex<double> w = W[j];
                std::complex<double> t = x[k + j] - x[k + j + half];
                x[k + j] += x[k + j + half];
                x[k + j + half] = t * w;
            }
        }
    }

    // --------------------------------------------------------------
    // 4. Conjugation
    // --------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (uint32_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
